## Plan — Slice 3: Tmux Resize Backend

### Goal
Replace stubs in tmux-mux.ts with real tmux resize implementations.

### Implementation

```
export function tmuxGetPaneHeight(pane: string): number {
  const result = execFileSync(
    "tmux", ["display-message", "-p", "-t", pane, "#{pane_height}"],
    { encoding: "utf8" },
  ).trim();
  return parseInt(result, 10) || 0;
}

export function tmuxResizeStack(panes: string[], targetLines: number): void {
  for (const pane of panes) {
    execFileSync(
      "tmux", ["resize-pane", "-t", pane, "-y", String(targetLines)],
      { encoding: "utf8" },
    );
  }
}
```

### Verification
Manual — requires running tmux instance. No unit tests (needs real mux).

## Plan — Slice 2: Herdr Resize Backend

### Goal
Replace stubs in herdr-mux.ts with real herdr resize implementations.

### Implementation

```
export function herdrGetPaneHeight(pane: string): number {
  const result = execFileSync(
    "herdr", ["pane", "read", pane, "--source", "recent", "--lines", "1"],
    { encoding: "utf8" },
  );
  const heightMatch = result.match(/height[:\s]+(\d+)/i);
  return heightMatch ? parseInt(heightMatch[1], 10) : 0;
}

export function herdrResizeStack(panes: string[], targetHeight: number): void {
  for (const pane of panes) {
    execFileSync(
      "herdr", ["pane", "resize", pane, "--direction", "down", "--amount", String(targetHeight)],
      { encoding: "utf8" },
    );
  }
}
```

### Verification
Manual — requires running herdr instance. No unit tests (needs real mux).
